// Filter to client meetings and prepare Toggl entries
const events = $input.all().map(i => i.json);
const clientMeetings = [];

for (const event of events) {
  const attendees = (event.attendees || []).map(a => a.email);
  const domains = attendees.map(e => e.split('@')[1]).filter(d => d && !d.includes('gmail.com'));

  if (domains.length > 0) {
    const start = new Date(event.start?.dateTime || event.start?.date);
    const end = new Date(event.end?.dateTime || event.end?.date);
    const durationSec = Math.round((end - start) / 1000);

    clientMeetings.push({
      description: event.summary || 'Client Meeting',
      start: start.toISOString(),
      duration: durationSec,
      domain: domains[0],
      lookup_type: 'email_domain',
      lookup_value: domains[0]
    });
  }
}

return clientMeetings.map(m => ({ json: m }));

// Compare hours vs retainer and generate invoice summary
const timeData = $('Get Last Month\'s Time').first().json;
const clients = $('Get Retainer Info').all().map(i => i.json);

const groups = timeData.groups || [];
const summary = [];

for (const client of clients) {
  const togglProjectId = client['Toggl Project ID'];
  const retainerHours = parseFloat(client['Retainer Hours/Month'] || 0);
  const hourlyRate = parseFloat(client['Hourly Rate'] || 0);

  // Find matching Toggl project
  const projectGroup = groups.find(g => String(g.id) === String(togglProjectId));
  const actualSeconds = projectGroup?.sub_groups?.reduce((sum, sg) => sum + (sg.seconds || 0), 0) || 0;
  const actualHours = Math.round(actualSeconds / 3600 * 10) / 10;

  const delta = actualHours - retainerHours;
  const status = delta > 2 ? 'OVER' : delta < -5 ? 'UNDER' : 'ON TRACK';
  const invoiceAmount = retainerHours > 0 
    ? hourlyRate * retainerHours + Math.max(0, delta) * hourlyRate 
    : hourlyRate * actualHours;

  summary.push({
    client: client['Client Name'],
    retainer_hours: retainerHours,
    actual_hours: actualHours,
    delta: delta,
    status: status,
    hourly_rate: hourlyRate,
    invoice_amount: invoiceAmount
  });
}

const totalInvoice = summary.reduce((sum, s) => sum + s.invoice_amount, 0);

const emailBody = `<h2>Monthly Time & Invoice Summary</h2>
<p><strong>Period:</strong> Last month</p>
<table border='1' cellpadding='5'>
<tr><th>Client</th><th>Retainer</th><th>Actual</th><th>Delta</th><th>Status</th><th>Invoice</th></tr>
${summary.map(s => `<tr><td>${s.client}</td><td>${s.retainer_hours}h</td><td>${s.actual_hours}h</td><td>${s.delta > 0 ? '+' : ''}${s.delta}h</td><td>${s.status}</td><td>$${s.invoice_amount.toLocaleString()}</td></tr>`).join('')}
</table>
<p><strong>Total: $${totalInvoice.toLocaleString()}</strong></p>`;

return [{ json: { summary, totalInvoice, emailBody } }];
